@js:
let url = String(source.getVariable()!=""?source.getVariable():source.getKey()).replace(/\/$/, '') 
let arr = []
let push = (title, url, type) => arr.push({
  title: title,
  url: url,
  style: {
    layout_flexGrow: 1,
    layout_flexBasisPercent: type
  }
})

push("🏷️全部分类🏷️", "", 1)
let res = org.jsoup.Jsoup.parse(java.ajax(url))
let lis = res.select('.nav a');
for (let i = 0; i < lis.length; i++) {
    let text = lis[i].text();
    let href = url + String(lis[i].attr('href')).replace(/\.html/g,"_\{\{page\}\}\.html");
    push(text, href, 0.25);
}
JSON.stringify(arr)

