         v=java.md5Encode(i);
        bytes = i.getBytes();
        bytes2 = v.getBytes();
        ivs=[];
        for (i = 0; i < 16; i++) {
            ivs[i] = (bytes2[i] ^ bytes[i]) ^ (-1); 
        }
       key = SecretKeySpec(ks, "AES");  
