@js:
function tryDecodeAsUrl(val) {
    try {
        val = String(val).trim();
        let decoded = java.base64Decode(val);
        if (decoded && /\/\d+\.html$/.test(decoded)) {
            return decoded;
        }
    } catch (e) {}
    return null;
}

function isLikelyTitle(val) {
    return /[\u4e00-\u9fa5]|^[\d\.]+$/.test(val);
}

const doc = org.jsoup.Jsoup.parse(result);
const lis = doc.select("ol li");
const chapterData = [];

lis.forEach(function(li) {
    let a = li.selectFirst("a");
    if (!a) return;

    let allAttrs = [];
    [li, a].forEach(function(el) {
        let attrs = el.attributes();
        for (let i = 0; i < attrs.size(); i++) {
            let attr = attrs.asList().get(i);
            let key = String(attr.getKey());
            let val = String(attr.getValue());
            if (key.startsWith("data-")) {
                allAttrs.push({ key: key, val: val });
            }
        }
    });

    let intValues = [];
    let strValues = [];
    allAttrs.forEach(function(item) {
        let num = parseInt(item.val, 10);
        if (!isNaN(num) && String(num) === item.val) {
            intValues.push(num);
        } else {
            strValues.push(item.val);
        }
    });
    let url = null;
    allAttrs.some(function(item) {
        let u = tryDecodeAsUrl(item.val);
        if (u) {
            url = u;
            return true;
        }
        return false;
    });
    if (!url) return;

    let title = null;
    strValues.some(function(val) {
        if (isLikelyTitle(val)) {
            title = val;
            return true;
        }
        return false;
    });

    chapterData.push({ url: url, title: title, intValues: intValues });
});

function sortChapters(data) {
  // 检测是否全局严格递增
  const isStrictlyIncreasing = (arr, idx) => {
    for (let i = 1; i < arr.length; i++) {
      if (arr[i].intValues[idx] <= arr[i-1].intValues[idx]) {
        return false;
      }
    }
    return true;
  };

  // 确定排序索引：递增列是显示序号，另一列用于排序
  let sortIndex;
  if (isStrictlyIncreasing(data, 0)) {
    sortIndex = 1; // 第0列递增，按第1列排序
  } else if (isStrictlyIncreasing(data, 1)) {
    sortIndex = 0; // 第1列递增，按第0列排序
  } else {
    // 兜底：如果都不递增，默认按第1列排序
    sortIndex = 1;
  }

  // 排序并移除 intValues
  return data
    .sort((a, b) => a.intValues[sortIndex] - b.intValues[sortIndex])
    .map(({ url, title }) => ({ url, title }));
}

sortChapters(chapterData);

