function base64(_str){
	var staticchars="PAhw7UT1B0a9kQDKZsjIASmOezxYG4CHo5Jyfg2b8FLpEvRr3WtVnlqMidu6oN";
	var encodechars="";
	for(var i=0;i<_str.length;i++){
		var num0=staticchars.indexOf(_str[i]);
		var code=num0==-1 ? _str[i] : staticchars[(num0+3)%62];
		var num1=parseInt(Math.random()*62,10);
		var num2=parseInt(Math.random()*62,10);
		encodechars += staticchars[num1]+code+staticchars[num2]
		}
	return encodechars
};

