    push("🔥分类小说🔥", null, 1);
    for (i in a) {
        title = a[i].text();
        url = a[i].attr("href");
        size = 0.33;
        title = String(title).replace(/\s/g, ""); 
        url = baseUrl + String(url).replace(/\/\d+\/$/, "/") + "{{page}}/"; 
        push(title, url, size);
    }
} 
