  title,
  url,
  style: {layout_flexBasisPercent: size}
})

let list = categories.map(([title, id]) => 
  obj(title, tpl.replace("$$", id), 0.2)
)

// 在线获取书单（只获取第一页）
try {
  let bookList = java.get("chamabooks_bookList");
  let bookListData = [];
  if (bookList) {
    try {
      bookListData = JSON.parse(bookList);
    } catch (e) {
      java.log("缓存数据解析失败: " + e.message);
    }
  }

  if (!Array.isArray(bookListData) || bookListData.length === 0) {
    let html = java.ajax("https://www.chamabooks.net/main?c=100");
    if (html) {
      let doc = org.jsoup.Jsoup.parse(html);
      let bookListEl = doc.select(".novel-item h4 a");

      if (bookListEl && bookListEl.size() > 0) {
        bookListData.push(obj("书单", "", 1));

        bookListEl.forEach(el => {
          let n = String(el.text()).trim();
          let u = String(el.attr("href"));
          bookListData.push(obj(n, u, 0.9));
        });

        java.put("chamabooks_bookList", JSON.stringify(bookListData));
      }
    }
  }

  if (bookListData.length > 0) {
    list = list.concat(bookListData);
  }

} catch (e) {
  java.log("获取书单失败: " + e.message);
}

JSON.stringify(list);

