function decodeContent(encodedContent, replaceMap) {
    var decodedContent = encodedContent;
    for (var key in replaceMap) {
        if (replaceMap.hasOwnProperty(key)) {
            var value = replaceMap[key];
            var regex = new RegExp(key, "g");
            decodedContent = decodedContent.replace(regex, String.fromCharCode(parseInt(value, 16)));
        }
    }
    return decodedContent;
}

